38	                | [Exp] ";"
39	                | Block
40	                | "return" Exp ";";
41	
42	Exp           ::= LOrExp;
43	LVal          ::= IDENT;
44	PrimaryExp    ::= "(" Exp ")" | LVal | Number;
45	Number        ::= INT_CONST;
